class AccessToken(db.Model):
    """Represents an OAuth 2.0 access token stored in the database."""
    __tablename__ = 'access_tokens'

    id = db.Column(db.Integer, primary_key=True)
    token = db.Column(db.String(255), unique=True, nullable=False, index=True)
    token_type = db.Column(db.String(40), default='Bearer')
    scope = db.Column(db.Text, default='')
    expires_at = db.Column(db.DateTime, nullable=False)
    is_revoked = db.Column(db.Boolean, default=False)
    created_at = db.Column(db.DateTime, default=datetime.utcnow)

    user_id = db.Column(db.Integer, db.ForeignKey('users.id'), nullable=False)
    client_id = db.Column(db.String(48), db.ForeignKey('oauth_clients.id'), nullable=False)

    def is_expired(self):
        return datetime.utcnow() > self.expires_at

    def is_valid(self):
        return not self.is_revoked and not self.is_expired()

    def has_scope(self, required_scope):
        if not required_scope:
            return True
        token_scopes = set(self.scope.split())
        required_scopes = set(required_scope.split()) if isinstance(required_scope, str) else set(required_scope)
        return required_scopes.issubset(token_scopes)

    def to_dict(self):
        return {
            'token': self.token,
            'token_type': self.token_type,
            'scope': self.scope,
            'expires_at': self.expires_at.isoformat(),
            'is_revoked': self.is_revoked,
            'user_id': self.user_id,
            'client_id': self.client_id
        }

    def __repr__(self):
        return f'<AccessToken {self.token[:8]}...>'


