# --- Token Validation Logic ---

def extract_token_from_request():
    """Extract the Bearer token from the Authorization header or query parameters."""
    # Check Authorization header first
    auth_header = request.headers.get('Authorization', '')
    if auth_header.startswith('Bearer '):
        return auth_header[7:].strip()

    # Fallback to query parameter (not recommended for production)
    token = request.args.get('access_token')
    if token:
        return token.strip()

    # Check form body
    token = request.form.get('access_token')
    if token:
        return token.strip()

    return None


def validate_token(token_string, required_scope=None):
    """
    Validate an access token by checking the database.
    Returns (token_obj, error_dict) tuple.
    """
    if not token_string:
        return None, {
            'error': 'missing_token',
            'error_description': 'Access token is required.'
        }

    # Look up token in database
    token_obj = AccessToken.query.filter_by(token=token_string).first()

    if token_obj is None:
        return None, {
            'error': 'invalid_token',
            'error_description': 'The access token is invalid.'
        }

    # Check if token is revoked
    if token_obj.is_revoked:
        return None, {
            'error': 'invalid_token',
            'error_description': 'The access token has been revoked.'
        }

    # Check if token is expired
    if token_obj.is_expired():
        return None, {
            'error': 'invalid_token',
            'error_description': 'The access token has expired.'
        }

    # Check if the associated user is still active
    user = User.query.get(token_obj.user_id)
    if user is None or not user.is_active:
        return None, {
            'error': 'invalid_token',
            'error_description': 'The resource owner is inactive or does not exist.'
        }

    # Check if the associated client is still active
    client = OAuthClient.query.get(token_obj.client_id)
    if client is None or not client.is_active:
        return None, {
            'error': 'invalid_token',
            'error_description': 'The client application is inactive or does not exist.'
        }

    # Check scope
    if required_scope and not token_obj.has_scope(required_scope):
        return None, {
            'error': 'insufficient_scope',
            'error_description': f'The token does not have the required scope: {required_scope}'
        }

    return token_obj, None


def log_token_validation(token_string, result, detail=None):
    """Log a token validation attempt to the audit log."""
    try:
        token_prefix = token_string[:8] + '...' if token_string and len(token_string) > 8 else token_string
        log_entry = TokenAuditLog(
            token_prefix=token_prefix,
            endpoint=request.path,
            method=request.method,
            ip_address=request.remote_addr,
            result=result,
            detail=detail
        )
        db.session.add(log_entry)
        db.session.commit()
    except Exception:
        db.session.rollback()


# --- Decorator ---

def require_oauth(scope=None):
    """
    Decorator to protect API endpoints with OAuth 2.0 token validation.

    Usage:
        @app.route('/api/resource')
        @require_oauth('read')
        def get_resource():
            user = g.current_user
            ...

        @app.route('/api/public-but-authenticated')
        @require_oauth()
        def get_data():
            ...
    """
    def decorator(f):
        @functools.wraps(f)
        def decorated_function(*args, **kwargs):
            token_string = extract_token_from_request()
            token_obj, error = validate_token(token_string, required_scope=scope)

            if error:
                error_type = error.get('error', 'invalid_token')
                log_token_validation(token_string, error_type, error.get('error_description'))

                status_code = 401
                headers = {'WWW-Authenticate': 'Bearer'}

                if error_type == 'insufficient_scope':
                    status_code = 403
                    headers['WWW-Authenticate'] = f'Bearer scope="{scope}"'
                elif error_type == 'missing_token':
                    status_code = 401
                    headers['WWW-Authenticate'] = 'Bearer realm="api"'

                response = jsonify(error)
                response.status_code = status_code
                for key, value in headers.items():
                    response.headers[key] = value
                return response

            # Set current user, token, and client in flask g context
            g.current_token = token_obj
            g.current_user = User.query.get(token_obj.user_id)
            g.current_client = OAuthClient.query.get(token_obj.client_id)

            log_token_validation(token_string, 'success')

            return f(*args, **kwargs)
        return decorated_function
    return decorator


