@app.route('/api/tokeninfo', methods=['GET', 'POST'])
def token_info():
    """Introspection-like endpoint to check token validity."""
    token_string = extract_token_from_request()
    if not token_string:
        token_string = request.json.get('token') if request.is_json else None

    if not token_string:
        return jsonify({'active': False, 'error': 'No token provided'}), 400

    token_obj, error = validate_token(token_string)

    if error:
        return jsonify({'active': False, **error}), 200

    user = User.query.get(token_obj.user_id)
    return jsonify({
        'active': True,
        'scope': token_obj.scope,
        'client_id': token_obj.client_id,
        'username': user.username if user else None,
        'token_type': token_obj.token_type,
        'exp': int(token_obj.expires_at.timestamp()),
        'iat': int(token_obj.created_at.timestamp()),
        'sub': str(token_obj.user_id)
    }), 200


